import numpy as np

# Minimal Module infrastructure (from 4.15)
class Module:
    def forward(self, x):
        raise NotImplementedError
    def __call__(self, x):
        return self.forward(x)
    def parameters(self):
        params = []
        for attr_name in vars(self):
            attr = getattr(self, attr_name)
            if isinstance(attr, np.ndarray):
                params.append(attr)
            elif isinstance(attr, Module):
                params.extend(attr.parameters())
            elif isinstance(attr, list):
                for item in attr:
                    if isinstance(item, Module):
                        params.extend(item.parameters())
        return params

class Linear(Module):
    def __init__(self, in_f, out_f):
        lim = np.sqrt(6 / (in_f + out_f))
        self.weight = np.random.uniform(-lim, lim, (in_f, out_f))
        self.bias = np.zeros(out_f)
    def forward(self, x):
        self._x = x
        return x @ self.weight + self.bias

class ReLU(Module):
    def forward(self, x):
        self._x = x
        return np.maximum(0, x)

class Sequential(Module):
    def __init__(self, *modules):
        self.layers = list(modules)
    def forward(self, x):
        for layer in self.layers:
            x = layer(x)
        return x
    def parameters(self):
        params = []
        for layer in self.layers:
            params.extend(layer.parameters())
        return params


class MSELoss:
    def __call__(self, pred: np.ndarray, target: np.ndarray) -> float:
        self.pred = pred
        self.target = target.reshape(pred.shape)
        self.N = pred.shape[0]
        return float(np.mean(0.5 * (pred - self.target) ** 2))

    def backward(self) -> np.ndarray:
        return (self.pred - self.target) / self.N


class SGD:
    def __init__(self, params: list, lr: float = 0.01):
        self.params = params
        self.lr = lr

    def zero_grad(self) -> None:
        for p in self.params:
            if hasattr(p, 'grad'):
                p.grad = None

    def step(self) -> None:
        for p in self.params:
            if hasattr(p, 'grad') and p.grad is not None:
                p -= self.lr * p.grad


def _backprop_sequential(model, grad_out):
    """Manual backprop through Sequential(Linear, ReLU, Linear)."""
    layers = model.layers
    d = grad_out
    for layer in reversed(layers):
        if isinstance(layer, Linear):
            layer.weight.grad = layer._x.T @ d
            layer.bias.grad = d.sum(axis=0)
            d = d @ layer.weight.T
        elif isinstance(layer, ReLU):
            d = d * (layer._x > 0)
    return d


def train(
    model,
    X: np.ndarray,
    y: np.ndarray,
    lr: float = 0.01,
    epochs: int = 100,
    batch_size: int = None
) -> list:
    criterion = MSELoss()
    optimizer = SGD(model.parameters(), lr=lr)
    N = X.shape[0]
    loss_history = []

    for epoch in range(epochs):
        if batch_size is None:
            batches = [(X, y)]
        else:
            indices = np.random.permutation(N)
            batches = [
                (X[indices[i:i+batch_size]], y[indices[i:i+batch_size]])
                for i in range(0, N, batch_size)
            ]

        epoch_losses = []
        for X_b, y_b in batches:
            # Forward
            pred = model(X_b)
            loss = criterion(pred, y_b)
            epoch_losses.append(loss)

            # Backward
            optimizer.zero_grad()
            grad_out = criterion.backward()
            _backprop_sequential(model, grad_out)

            # Update
            optimizer.step()

        loss_history.append(float(np.mean(epoch_losses)))

    return loss_history
